def parse_csv_line(line):
    """Parse a single CSV line into a list of field values.
    Handles quoted fields, escaped quotes (""), commas/newlines inside quotes.
    """
    fields = []
    current = []
    in_quotes = False
    field_start = True  # True when at the start of a field (before any data/quote)
    i = 0
    n = len(line)

    while i < n:
        ch = line[i]

        if in_quotes:
            if ch == '"':
                # Possible escaped quote or end of quoted field
                if i + 1 < n and line[i + 1] == '"':
                    # Escaped quote
                    current.append('"')
                    i += 1  # Skip the second quote of the pair
                else:
                    # End of quoted field
                    in_quotes = False
            else:
                current.append(ch)
        else:
            if ch == ',':
                # End of field
                fields.append(''.join(current))
                current = []
                field_start = True
            elif ch == '\n' or ch == '\r':
                # End of record if not in quotes; consume CRLF as a unit
                if ch == '\r' and i + 1 < n and line[i + 1] == '\n':
                    i += 1
                break
            elif ch == '"':
                # Start of quoted field only allowed at field start per RFC 4180
                if field_start:
                    in_quotes = True
                else:
                    # Quote inside unquoted field: treat as literal
                    current.append('"')
                    field_start = False
            else:
                current.append(ch)
                field_start = False

        i += 1

    # Append the last field
    fields.append(''.join(current))
    return fields

